SELECT country_id, rank_by_total, total
FROM medals
ORDER BY total DESC;

SELECT COUNT(DISTINCT country_id) AS total_countries
FROM medals
WHERE event_id = 1;

SELECT gold, silver
FROM medals
WHERE country_id = 0 AND event_id = 1;

SELECT COUNT(athlete_id) AS participant_count
FROM event_participants
WHERE event_id = 1;

SELECT COUNT(*) AS medal_count
FROM medal_awards
WHERE award_date = '2021-07-26';

SELECT event_name, year
FROM olympic_events
ORDER BY year DESC;
